const base64Result = $input.first().json;
const dados = $('Dados do Áudio').first().json;

const base64 = base64Result?.base64 || base64Result?.data || '';
const mimetype = base64Result?.mimetype || 'audio/ogg; codecs=opus';
const temBase64 = base64 && base64.length > 100;

const mimetypeMap = {
  'audio/ogg': 'ogg',
  'audio/ogg; codecs=opus': 'ogg',
  'audio/mp4': 'mp4',
  'audio/mpeg': 'mp3',
  'audio/wav': 'wav',
  'audio/webm': 'webm'
};
const ext = mimetypeMap[mimetype] || 'ogg';

return [{
  json: {
    ...dados,
    audio_base64: base64,
    audio_mimetype: mimetype,
    audio_filename: `audio_${dados.session_id}.${ext}`,
    tem_audio: temBase64
  }
}];

const base64Result = $input.first().json;
const dados = $('Dados do Documento').first().json;

const base64 = base64Result?.base64 || base64Result?.data || '';
const mimetype = base64Result?.mimetype || 'image/jpeg';
const temBase64 = base64 && base64.length > 100;

const isImagem = mimetype.startsWith('image/');
const isPdf = mimetype === 'application/pdf';

return [{
  json: {
    ...dados,
    doc_base64: base64,
    doc_mimetype: mimetype,
    tem_doc: temBase64,
    is_imagem: isImagem,
    is_pdf: isPdf
  }
}];

const leadResult = $('Busca Lead no CRM1').first().json;
const slotsResult = $input.first().json;
const dados = $('Dados do Agendamento').first().json;

const lead = leadResult?.encontrado ? leadResult.lead : null;
const slots = slotsResult?.slots || [];

// Formata slots para exibição amigável
const slotsFormatados = slots.slice(0, 5).map((slot, i) => {
  const d = new Date(slot);
  const dias = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  const meses = ['jan', 'fev', 'mar', 'abr', 'mai', 'jun', 'jul', 'ago', 'set', 'out', 'nov', 'dez'];
  return {
    numero: i + 1,
    iso: slot,
    texto: `${i + 1}. ${dias[d.getDay()]}, ${d.getDate()} de ${meses[d.getMonth()]} às ${String(d.getHours()).padStart(2,'0')}h${String(d.getMinutes()).padStart(2,'0')}`
  };
});

return [{
  json: {
    ...dados,
    lead_encontrado: !!lead,
    lead_nome: lead?.nome || dados.nome_pessoa,
    lead_protocolo: lead?.protocolo || '',
    lead_area: lead?.areaJuridicaProvavel || '',
    lead_atendimento_id: lead?.atendimentoAtual?.id || '',
    slots_disponiveis: slotsFormatados,
    slots_texto: slotsFormatados.map(s => s.texto).join('\n'),
    tem_slots: slotsFormatados.length > 0
  }
}];

