parameters.jsCode:
// Armazena os slots disponíveis no Redis para a próxima mensagem
// (quando o cliente responder com o número escolhido)
// O fluxo principal vai identificar a escolha e acionar o webhook de confirmação

const dados = $('Prepara Slots e Contexto').first().json;
const slots = dados.slots_disponiveis;

// A confirmação será tratada pelo fluxo principal (AI Agent)
// quando o cliente digitar o número do horário
// O Redis Chat Memory já mantém o contexto da conversa

return [{ json: {
  status: 'slots_oferecidos',
  session_id: dados.session_id,
  slots_enviados: slots.length
}}];

const agendaResult = $input.first().json;
const dados = $('Dados Confirmação').first().json;

const dataHora = new Date(dados.slot_escolhido_iso);
const dias = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];
const meses = ['janeiro', 'fevereiro', 'março', 'abril', 'maio', 'junho', 'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro'];

const dataFormatada = `${dias[dataHora.getDay()]}, ${dataHora.getDate()} de ${meses[dataHora.getMonth()]} às ${String(dataHora.getHours()).padStart(2,'0')}h${String(dataHora.getMinutes()).padStart(2,'0')}`;

return [{
  json: {
    ...dados,
    agendamento_id: agendaResult?.agendamentoId || '',
    data_formatada: dataFormatada
  }
}];

const result = $input.first().json;
const agendamentos = result?.agendamentos || [];

if (!agendamentos.length) {
  return [{ json: { total: 0, lembretes: [] } }];
}

// Filtra os que são amanhã (24h antes)
const amanha = new Date();
amanha.setDate(amanha.getDate() + 1);
amanha.setHours(0,0,0,0);
const amanhaFim = new Date(amanha);
amanhaFim.setHours(23,59,59,999);

const lembretes = agendamentos.filter(ag => {
  const d = new Date(ag.dataHora);
  return d >= amanha && d <= amanhaFim && !ag.lembrete24hEnviado;
});

return lembretes.map(ag => ({
  json: {
    agendamentoId: ag.id,
    remoteJid: ag.lead?.remoteJid || '',
    instancia: ag.lead?.instancia || $env.EVOLUTION_INSTANCE || 'italoribeiro',
    nomeCliente: ag.lead?.nome || 'Cliente',
    dataHora: ag.dataHora,
    tipoConsulta: ag.tipo
  }
}));

const ag = $input.first().json;
if (!ag.remoteJid) return [];

const d = new Date(ag.dataHora);
const horas = String(d.getHours()).padStart(2,'0');
const mins = String(d.getMinutes()).padStart(2,'0');
const dias = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];

return [{ json: {
  ...ag,
  mensagem_lembrete: `Olá, ${ag.nomeCliente}. Lembramos que amanhã você tem consulta agendada no escritório Ítalo Ribeiro Advogados às ${horas}h${mins}. Lembre-se de trazer os documentos relacionados ao seu caso. Qualquer dúvida, estamos à disposição.`
}}];

const dados = $('Dados').first().json;
const contexto = $('Prepara Contexto').first().json;
const redis = $input.first().json;
const textoOriginal = String(dados.mensagem || '').trim();
const texto = textoOriginal.toLowerCase();

function normalize(value) {
  return String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

const normalizado = normalize(texto);

let slotsPendentes = [];
try {
  const bruto = redis?.slotsPending || '[]';
  const parsed = bruto ? JSON.parse(bruto) : [];
  slotsPendentes = Array.isArray(parsed) ? parsed : [];
} catch {
  slotsPendentes = [];
}

let slotEscolhido = null;
const numero = normalizado.match(/\b([1-9]|10)\b/);
if (numero) {
  const indice = Number(numero[1]) - 1;
  if (slotsPendentes[indice]) slotEscolhido = slotsPendentes[indice];
}

if (!slotEscolhido && slotsPendentes.length) {
  const horario = normalizado.match(/\b([01]?\d|2[0-3])[:h]([0-5]\d)\b/);
  if (horario) {
    const hh = String(horario[1]).padStart(2, '0');
    const mm = String(horario[2]).padStart(2, '0');
    slotEscolhido =
      slotsPendentes.find((slot) => {
        const d = new Date(slot.startAt || slot.iso);
        return String(d.getHours()).padStart(2, '0') === hh && String(d.getMinutes()).padStart(2, '0') === mm;
      }) || null;
  }
}

const pediuAgendamento = /(agendar|agendamento|marcar|consulta|horario|horarios|disponibilidade|agenda)/.test(normalizado);
const confirmouTexto = /(confirmo|confirmar|pode ser|fechado|esse horario|este horario|quero esse)/.test(normalizado);

if (!slotEscolhido && confirmouTexto && slotsPendentes.length === 1) {
  slotEscolhido = slotsPendentes[0];
}

const acao = slotEscolhido ? 'confirmar' : (pediuAgendamento ? 'oferecer' : 'normal');
const startIso = slotEscolhido ? (slotEscolhido.startAt || slotEscolhido.iso || '') : '';
const endIso = slotEscolhido
  ? (slotEscolhido.endAt || new Date(new Date(startIso).getTime() + 30 * 60000).toISOString())
  : '';

return [{
  json: {
    ...contexto,
    acao_agendamento: acao,
    texto_cliente: textoOriginal,
    slots_pendentes: slotsPendentes,
    slot_escolhido_iso: startIso,
    slot_escolhido_end: endIso,
  },
}];

const itens = $input.all().map((item) => item.json);
let slots = [];

if (Array.isArray(itens[0])) {
  slots = itens[0];
} else if (Array.isArray(itens[0]?.slots)) {
  slots = itens[0].slots;
} else {
  slots = itens.filter((item) => item && (item.startAt || item.endAt));
}

const dias = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sab'];
const meses = ['jan', 'fev', 'mar', 'abr', 'mai', 'jun', 'jul', 'ago', 'set', 'out', 'nov', 'dez'];

const slotsFormatados = slots.slice(0, 6).map((slot, index) => {
  const startAt = slot.startAt || slot.iso || slot;
  const endAt = slot.endAt || new Date(new Date(startAt).getTime() + 30 * 60000).toISOString();
  const d = new Date(startAt);
  const texto =
    (index + 1) + '. ' + dias[d.getDay()] + ', ' + d.getDate() + ' de ' + meses[d.getMonth()] +
    ' as ' + String(d.getHours()).padStart(2, '0') + 'h' + String(d.getMinutes()).padStart(2, '0');
  return {
    numero: index + 1,
    startAt,
    endAt,
    texto,
  };
});

return [{
  json: {
    slots_disponiveis: slotsFormatados,
    slots_texto: slotsFormatados.map((slot) => slot.texto).join('\n'),
    tem_slots: slotsFormatados.length > 0,
  },
}];

